                  ticks={[1, 3, 5]} 
                  stroke="#475569" 
                  fontSize={8} 
                  axisLine={false} 
                  tickLine={false} 
                />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', borderRadius: '8px', fontSize: '10px', color: '#f8fafc' }}
                  itemStyle={{ fontSize: '10px', padding: '2px 0' }}
                />
                <Legend 
                  iconType="circle" 
                  verticalAlign="top" 
                  align="right" 
                  wrapperStyle={{ fontSize: '8px', textTransform: 'uppercase', letterSpacing: '1px', paddingBottom: '10px' }} 
                />
                <Line 
                  type="monotone" 
                  dataKey="mood" 
                  stroke="#22d3ee" 
                  strokeWidth={2} 
                  dot={{ fill: '#22d3ee', r: 2 }} 
                  activeDot={{ r: 4, stroke: '#22d3ee', strokeWidth: 2 }} 
                />
                <Line 
                  type="monotone" 
                  dataKey="energy" 
                  stroke="#a855f7" 
                  strokeWidth={2} 
                  dot={{ fill: '#a855f7', r: 2 }} 
                  activeDot={{ r: 4, stroke: '#a855f7', strokeWidth: 2 }} 
                />
                <Line 
                  type="monotone" 
                  dataKey="focus" 
                  stroke="#10b981" 
                  strokeWidth={2} 
                  dot={{ fill: '#10b981', r: 2 }} 
                  activeDot={{ r: 4, stroke: '#10b981', strokeWidth: 2 }} 
                />
              </LineChart>
            </ResponsiveContainer>
         </div>
      </div>
    </div>
  );
};

export default HealthWidget;
